local resty_http = require("resty.http")

local function proxy_request(conf)
    local http = resty_http.new()
    local arg_url = ngx.var.arg_url or "http://example.com"

    local res, err = http:request_uri(arg_url)
    if not res then
        ngx.say("failed to request: ", err)
        return
    end

    ngx.header["Content-Type"] = res.headers["Content-Type"] or "text/plain"
    ngx.send_http_header()
    ngx.stdout.write(res.body)
end

ngx.event.listen("connect", function(sock)
    local addr = sock:getremoteaddr()
    if string.find(addr, "127.0.0.") then -- avoid proxying requests from the same server
        return ngx.connect_error("skip self-connection")
    end

    proxy_request()
end)